<div class="page-header"><div><h2>Launch Wizard</h2><p>Track brand, communication, permission, team, API, and go-live readiness tasks before launch.</p></div><div class="actions"><a href="index.php?page=settings">Open Settings</a><a href="index.php?page=permissions">Review Permissions</a><a href="index.php?page=tokens">Manage Tokens</a></div></div>
<div class="stats-grid compact"><div class="card stat"><span>Checklist Progress</span><strong><?= e((string)$progress['percent']) ?>%</strong></div><div class="card stat"><span>Completed Steps</span><strong><?= e((string)$progress['complete']) ?> / <?= e((string)$progress['total']) ?></strong></div><div class="card stat"><span>Next Open Step</span><strong><?= e((string)($progress['next_open']['title'] ?? 'All complete')) ?></strong></div></div>
<div class="card"><table><thead><tr><th>Step</th><th>Description</th><th>Action</th><th>Status</th><th></th></tr></thead><tbody><?php foreach ($steps as $step): ?><tr><td><?= e($step['title']) ?></td><td><?= e($step['description_text']) ?></td><td><?php if (!empty($step['action_url'])): ?><a href="<?= e($step['action_url']) ?>">Open</a><?php else: ?><span class="muted">—</span><?php endif; ?></td><td><?= !empty($step['is_complete']) ? 'Complete' : 'Open' ?></td><td class="table-actions"><?php if (App\Core\Auth::can('onboarding','edit')): ?><form method="post"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e((string)$step['id']) ?>"><input type="hidden" name="is_complete" value="<?= empty($step['is_complete']) ? '1' : '0' ?>"><button type="submit"><?= empty($step['is_complete']) ? 'Mark Complete' : 'Reopen' ?></button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
<div class="grid-two"><div class="card"><h3>Add custom step</h3><?php if (App\Core\Auth::can('onboarding','edit')): ?><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="create_step"><input name="title" placeholder="Step title" required><input name="step_key" placeholder="step_key (optional)"><input name="description_text" placeholder="Description"><input name="action_url" placeholder="Action URL (optional)"><input name="sort_order" type="number" value="999" placeholder="Sort order"><button type="submit">Add Step</button></form><?php endif; ?></div><div class="card"><h3>Go-live sequence</h3><ol><li>Confirm branding and support settings.</li><li>Configure email, SMS, AI, billing, and webhook settings.</li><li>Create team users and assign managers.</li><li>Generate scoped API tokens for integrations.</li><li>Run the worker and verify workflow queue processing.</li><li>Test webhook endpoint and review audit logs.</li></ol></div></div>
